import { Component, inject, OnInit } from '@angular/core';
import { AdminCasesService } from '../../../application/services/admin-cases.service';
import { DashboardStats, PendingTask, CaseItem } from '../../../application/models/backoffice.models';

@Component({
  selector: 'bo-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.css']
})
export class DashboardComponent implements OnInit {
  private readonly adminCasesService = inject(AdminCasesService);

  stats: DashboardStats | null = null;
  pendingTasks: PendingTask[] = [];
  recentCases: CaseItem[] = [];
  isLoading = true;

  ngOnInit(): void {
    this.loadDashboard();
  }

  loadDashboard(): void {
    this.isLoading = true;
    this.adminCasesService.getDashboardStats().subscribe({
      next: (stats) => {
        this.stats = stats;
        this.isLoading = false;
      },
      error: () => {
        this.stats = this.getDefaultStats();
        this.isLoading = false;
      }
    });

    this.adminCasesService.getPendingTasks().subscribe({
      next: (tasks) => {
        this.pendingTasks = tasks.slice(0, 5);
      },
      error: () => {
        this.pendingTasks = [];
      }
    });
  }

  private getDefaultStats(): DashboardStats {
    return {
      totalCases: 0,
      pendingCases: 0,
      casesInProgress: 0,
      completedToday: 0,
      overdueCases: 0,
      avgResolutionTime: '0h'
    };
  }
}
<div *ngIf="isLoading" class="flex items-center justify-center h-64">
  <div class="text-gray-500">Cargando dashboard...</div>
</div>

<div *ngIf="!isLoading">
  <!-- Stats cards -->
  <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
    <div class="bg-white rounded-lg shadow p-6">
      <div class="text-sm text-gray-500 mb-1">Total Expedientes</div>
      <div class="text-3xl font-bold text-gray-900">{{ stats?.totalCases || 0 }}</div>
    </div>
    <div class="bg-white rounded-lg shadow p-6">
      <div class="text-sm text-gray-500 mb-1">Pendientes</div>
      <div class="text-3xl font-bold text-yellow-600">{{ stats?.pendingCases || 0 }}</div>
    </div>
    <div class="bg-white rounded-lg shadow p-6">
      <div class="text-sm text-gray-500 mb-1">En Tramitacion</div>
      <div class="text-3xl font-bold text-blue-600">{{ stats?.casesInProgress || 0 }}</div>
    </div>
    <div class="bg-white rounded-lg shadow p-6">
      <div class="text-sm text-gray-500 mb-1">Completados Hoy</div>
      <div class="text-3xl font-bold text-green-600">{{ stats?.completedToday || 0 }}</div>
    </div>
  </div>

  <div class="grid grid-cols-1 lg:grid-cols-2 gap-6">
    <!-- Pending tasks -->
    <div class="bg-white rounded-lg shadow">
      <div class="px-6 py-4 border-b border-gray-200">
        <h3 class="text-lg font-semibold text-gray-900">Tareas Pendientes</h3>
      </div>
      <div class="p-6">
        <div *ngIf="pendingTasks.length === 0" class="text-gray-500 text-sm">
          No hay tareas pendientes
        </div>
        <ul class="space-y-3">
          <li *ngFor="let task of pendingTasks" class="flex items-center justify-between py-2 border-b border-gray-100 last:border-0">
            <div>
              <div class="font-medium text-gray-900">{{ task.caseTitle }}</div>
              <div class="text-sm text-gray-500">{{ task.taskName }}</div>
            </div>
            <span
              class="px-2 py-1 text-xs font-medium rounded-full"
              [class.bg-yellow-100]="task.priority === 'normal'"
              [class.text-yellow-800]="task.priority === 'normal'"
              [class.bg-red-100]="task.priority === 'urgent'"
              [class.text-red-800]="task.priority === 'urgent'"
            >
              {{ task.priority === 'urgent' ? 'Urgente' : 'Normal' }}
            </span>
          </li>
        </ul>
      </div>
    </div>

    <!-- Recent cases -->
    <div class="bg-white rounded-lg shadow">
      <div class="px-6 py-4 border-b border-gray-200">
        <h3 class="text-lg font-semibold text-gray-900">Actividad Reciente</h3>
      </div>
      <div class="p-6">
        <div class="text-gray-500 text-sm">
          Los expedientes apareceran aqui cuando se reciban datos del backend.
        </div>
      </div>
    </div>
  </div>
</div>
